class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    private let keychainService = "com.yourapp.biometric-auth"
    
    private init() {}
    
    func authenticateUser(completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, "Biometric authentication not available")
            return
        }
        
        let reason = "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, 
                              localizedReason: reason,
                              reply: { [weak self] success, error in
            DispatchQueue.main.async {
                if success {
                    self?.storeAuthenticationStatus()
                    completion(true, nil)
                } else {
                    let errorMessage = self?.getErrorMessage(error)
                    completion(false, errorMessage)
                }
            }
        })
    }
    
    func isUserAuthenticated() -> Bool {
        return getAuthenticationStatus()
    }
    
    func clearAuthenticationStatus() {
        UserDefaults.standard.set(false, forKey: "isUserAuthenticated")
        removeBiometricKey()
    }
    
    private func storeAuthenticationStatus() {
        UserDefaults.standard.set(true, forKey: "isUserAuthenticated")
        storeBiometricKey()
    }
    
    private func getAuthenticationStatus() -> Bool {
        return UserDefaults.standard.bool(forKey: "isUserAuthenticated")
    }
    
    private func getErrorMessage(_ error: Error?) -> String {
        guard let error = error as? LAError else { return "Authentication failed" }
        
        switch error.code {
        case .userCancel:
            return "Authentication cancelled"
        case .userFallback:
            return "Fallback authentication requested"
        case .systemCancel:
            return "System cancelled authentication"
        case .invalidContext:
            return "Invalid authentication context"
        case .notInteractive:
            return "Authentication not interactive"
        default:
            return "Authentication failed"
        }
    }
    
    private func storeBiometricKey() {
        let key = "biometric_key_\(UUID().uuidString)"
        let data = key.data(using: .utf8)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecValueData as String: data ?? Data()
        ]
        
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    private func removeBiometricKey() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService
        ]
        
        SecItemDelete(query as CFDictionary)
    }
}

